import{_ as e,I as l,f as i,i as d}from"./chunks/framework.BQlZKzZW.js";const _=JSON.parse('{"title":"Casual Think","description":"","frontmatter":{"date":"","draft":false,"title":"Casual Think","BookToC":true,"outline":[1,8],"sidebar":false},"headers":[],"relativePath":"life/casual-think.md","filePath":"life/casual-think.md"}'),r={name:"life/casual-think.md"};function n(o,a,t,c,s,h){return l(),i("div",null,[...a[0]||(a[0]=[d('<h1 id="casual-think" tabindex="-1">Casual Think <a class="header-anchor" href="#casual-think" aria-label="Permalink to “Casual Think”">​</a></h1><h2 id="_2026" tabindex="-1">2026 <a class="header-anchor" href="#_2026" aria-label="Permalink to “2026”">​</a></h2><h3 id="_2026-05" tabindex="-1">2026-05 <a class="header-anchor" href="#_2026-05" aria-label="Permalink to “2026-05”">​</a></h3><h4 id="_2026-05-26-tuesday" tabindex="-1">2026-05-26 Tuesday <a class="header-anchor" href="#_2026-05-26-tuesday" aria-label="Permalink to “2026-05-26 Tuesday”">​</a></h4><ul><li>claude code 上配置 deepseek v4，没有在用阿里百炼的 coding plan了。deepseek v4 按量付费，多个对话同时跑不会429。这两天工作高频使用，一天的费用是10块，先用一个月看吧，说不定比200块一个月的订阅便宜呢。即使贵一点，它的效果也还是可以的，加上它可以并发跑，响应速度也不慢</li></ul><h4 id="_2026-05-25-monday" tabindex="-1">2026-05-25 Monday <a class="header-anchor" href="#_2026-05-25-monday" aria-label="Permalink to “2026-05-25 Monday”">​</a></h4><ul><li>广州开始热起来了，下班骑车回去第一件事必须得冲一个澡</li></ul><h4 id="_2026-05-15-friday" tabindex="-1">2026-05-15 Friday <a class="header-anchor" href="#_2026-05-15-friday" aria-label="Permalink to “2026-05-15 Friday”">​</a></h4><ul><li>去年的工作如果有好好用一下AI的话，那真的是能做的更好，更少犯错</li></ul><h4 id="_2026-05-14" tabindex="-1">2026-05-14 <a class="header-anchor" href="#_2026-05-14" aria-label="Permalink to “2026-05-14”">​</a></h4><ul><li>现在使用 <code>claude code</code> 配置的模型是 百炼的 coding plan，如果开2个对话，就老是会报 429，只能一个一个执行，好慢呀， 不知道有什么办法可以同时多开，这样效率就又能提升了 <ul><li>我在我的服务器上还有我的工作电脑上2个地方同时进行对话，还是会被429，指定不同的模型也不行，好像没有办法了</li></ul></li><li>使用 <code>plan mode</code> 一方面可以让你理清思路你想要让AI做什么，另一方面是可以规划好一批任务一次提交给AI，让AI可以持续运行把事情做完，效果更高 <ul><li>我发现即使是在 <code>plan mode</code> 下，它也不出完全不会改动你的工程，它还是会编辑你的工程文件</li></ul></li><li>在windows电脑上，我其实更想用 Terminal 来使用 claude code，感觉 Terminal 上的字体显示更舒服，用 IDEA 的话，有 claude code 的插件可以和 claude code cli 进行交互，我可以选中代码直接发送到cli，如果用 Terminal 就不行</li><li>其实系统中(一致性要求很高)有同步任务也不是说会有什么太大的问题，只要同步逻辑写对的不出问题</li></ul>',11)])])}const f=e(r,[["render",n]]);export{_ as __pageData,f as default};
